21	    public Game toGame(Event event, League league) {
22	        Competition competition = first(event.getCompetitions());
23	        if (competition == null) {
24	            return null;
25	        }
26	
27	        Team homeTeam = null;
28	        Team awayTeam = null;
29	
30	        List<Competitor> competitors = Optional.ofNullable(competition.getCompetitors()).orElse(List.of());
31	        for (Competitor competitor : competitors) {
32	            if (competitor == null || competitor.getTeam() == null) {
33	                continue;
34	            }
35	
36	            Team mappedTeam = toTeam(competitor, league);
37	            if (mappedTeam == null) {
38	                continue;
39	            }
40	
41	            if ("home".equalsIgnoreCase(competitor.getHomeAway())) {
42	                homeTeam = mappedTeam;
43	            } else if ("away".equalsIgnoreCase(competitor.getHomeAway())) {
44	                awayTeam = mappedTeam;
45	            }
46	        }
47	
48	        if (homeTeam == null || awayTeam == null) {
49	            return null;
50	        }
51	
52	        GameOdd odds = buildGameOdd(event, competition);
53	        Status status = competition.getStatus();
54	
55	        Game game = Game.builder()
56	                .id(Integer.parseInt(event.getId()))
57	                .league(league)
58	                .homeTeam(homeTeam)
59	                .gameOdd(odds)
60	                .homeRecordAtTimeOfGame(homeTeam.getRecord())
61	                .awayTeam(awayTeam)
62	                .awayRecordAtTimeOfGame(awayTeam.getRecord())
63	                .week(Optional.ofNullable(event.getWeek())
64	                        .map(Week::getNumber)
65	                        .orElse(0))
66	                .seasonType(Optional.ofNullable(event.getSeason())
67	                        .map(Season::getType)
68	                        .orElse(0))
69	                .year(Optional.ofNullable(event.getSeason())
70	                        .map(Season::getYear)
71	                        .orElse(0))
72	                .stadiumName(Optional.ofNullable(competition.getVenue())
73	                        .map(Venue::getFullName)
74	                        .orElse(null))
75	                .location(Optional.ofNullable(competition.getVenue())
76	                        .map(Venue::getAddress)
77	                        .map(Address::toString)
78	                        .orElse(""))
79	                .isoDate(ZonedDateTime.parse(competition.getStartDate(),
80	                        DateTimeFormatter.ISO_DATE_TIME).toInstant())
81	                .homeScore(getScore("home", competitors))
82	                .awayScore(getScore("away", competitors))
83	                .period(Optional.ofNullable(status)
84	                        .map(Status::getPeriod)
85	                        .map(String::valueOf)
86	                        .orElse(null))
87	                .shortPeriod(Optional.ofNullable(status)
88	                        .map(Status::getType)
89	                        .map(StatusType::getShortDetail)
90	                        .orElse(null))
91	                .channel(competition.getBroadcast())
92	                .gameStatus(Optional.ofNullable(status)
