94	                        .map(StatusType::getName)
95	                        .orElse(null))
96	                .finalGame(Optional.ofNullable(status)
97	                        .map(Status::getType)
98	                        .map(StatusType::getCompleted)
99	                        .orElse(null))
100	                .espnLink(firstLinkHref(event))
101	                .winner(getWinningTeamId(competition))
102	                .headline(Optional.ofNullable(competition.getNotes())
103	                        .orElse(List.of())
104	                        .stream()
105	                        .filter(Objects::nonNull)
106	                        .map(Note::getHeadline)
107	                        .filter(Objects::nonNull)
108	                        .findFirst()
109	                        .orElse(null))
110	                .possessionTeamId(Optional.ofNullable(competition.getSituation())
111	                        .map(Situation::getPossession)
112	                        .orElse(""))
113	                .homeTimeouts(Optional.ofNullable(competition.getSituation())
114	                        .map(Situation::getHomeTimeouts)
115	                        .orElse(0))
116	                .awayTimeouts(Optional.ofNullable(competition.getSituation())
117	                        .map(Situation::getAwayTimeouts)
118	                        .orElse(0))
