140	    private GameOdd buildGameOdd(Event event, Competition competition) {
141	        String spreadText = Optional.ofNullable(competition.getOdds())
142	                .orElse(List.of())
143	                .stream()
144	                .filter(Objects::nonNull)
145	                .map(Odds::getDetails)
146	                .filter(Objects::nonNull)
147	                .findFirst()
148	                .orElse(null);
149	
150	        if (spreadText == null) {
151	            return null;
152	        }
153	
154	        GameOdd odds = new GameOdd();
155	        odds.setId(Integer.parseInt(event.getId()));
156	        odds.setSpreadText(spreadText);
157	        return odds;
158	    }
159	
160	    private String firstLinkHref(Event event) {
161	        return Optional.ofNullable(event.getLinks())
162	                .orElse(List.of())
163	                .stream()
164	                .filter(Objects::nonNull)
165	                .map(Link::getHref)
166	                .filter(Objects::nonNull)
167	                .findFirst()
168	                .orElse(null);
169	    }
170	
171	    private int getWinningTeamId(Competition competition) {
172	        if (competition == null || competition.getCompetitors() == null) {
173	            return 0;
174	        }
175	
