178	                .filter(c -> Boolean.TRUE.equals(c.getWinner()))
179	                .map(Competitor::getTeam)
180	                .filter(Objects::nonNull)
181	                .map(com.tallyo.tallyo_backend.model.espn.scoreboard.Team::getId)
182	                .filter(Objects::nonNull)
183	                .findFirst()
184	                .orElse(0);
185	    }
