187	    private Team toTeam(Competitor competitor, League league) {
188	        com.tallyo.tallyo_backend.model.espn.scoreboard.Team espnTeam = competitor.getTeam();
189	        if (espnTeam == null || espnTeam.getId() == null) {
190	            return null;
191	        }
192	
193	        TeamKey teamId = new TeamKey(espnTeam.getId(), league);
194	        return Team.builder()
195	                .teamKey(teamId)
196	                .name(espnTeam.getDisplayName())
197	                .abbreviation(espnTeam.getAbbreviation())
198	                .logo(espnTeam.getLogo())
199	                .primaryColor(espnTeam.getColor())
200	                .alternateColor(espnTeam.getAlternateColor())
201	                .location(espnTeam.getLocation())
202	                .record(getOverallRecord(competitor))
203	                .homeRecord(getRecord(competitor, "home"))
204	                .roadRecord(getRecord(competitor, "road"))
205	                .score(competitor.getScore())
206	                .build();
