208	
209	    private String getScore(String homeAway, List<Competitor> competitors) {
210	        if (competitors == null) {
211	            return null;
212	        }
213	
214	        return competitors.stream()
215	                .filter(Objects::nonNull)
216	                .filter(c -> homeAway.equalsIgnoreCase(c.getHomeAway()))
217	                .map(Competitor::getScore)
218	                .findFirst()
219	                .orElse(null);
220	    }
221	
222	    private String getOverallRecord(Competitor competitor) {
223	        return getRecord(competitor);
224	    }
225	
226	    private String getRecord(Competitor competitor, String type) {
227	        return getRecordByType(competitor, type);
228	    }
229	
230	    private String getRecord(Competitor competitor) {
231	        if (competitor.getRecords() == null) {
232	            return null;
233	        }
234	        return competitor.getRecords().stream()
235	                .filter(Objects::nonNull)
236	                .map(Record::getSummary)
237	                .findFirst()
238	                .orElse(null);
239	    }
240	
241	    private String getRecordByType(Competitor competitor, String type) {
242	        if (competitor.getRecords() == null) {
243	            return null;
244	        }
245	
246	        return competitor.getRecords().stream()
247	                .filter(Objects::nonNull)
248	                .filter(r -> type.equalsIgnoreCase(r.getType()))
249	                .map(Record::getSummary)
250	                .findFirst()
251	                .orElse(null);
252	    }
253	
254	    private <T> T first(List<T> list) {
255	        if (list == null) {
256	            return null;
257	        }
258	
259	        return list.stream().filter(Objects::nonNull).findFirst().orElse(null);
260	    }
