158	    // Seeds/refreshes the current year's schedule for every league so the 20s
159	    // live-update job has upcoming games to trigger on. Schedule-only (no
160	    // per-game summary calls): one scoreboard request per league.
161	    private void refreshSchedules() {
162	        long startTime = System.currentTimeMillis();
163	        logger.info("Refreshing season schedules for all leagues");
164	        for (League league : League.values()) {
165	            try {
166	                List<Game> games = espnService.fetchGames(league, 0, false);
167	                int saved = saveScheduleGames(games);
168	                int pruned = pruneStaleScheduledGames(league, games);
169	                logger.info("Refreshed schedule for {}: saved {} of {} games, pruned {} stale",
170	                        league, saved, games.size(), pruned);
171	            } catch (Exception e) {
172	                logger.error("Schedule refresh failed for {}: {}", league, e.getMessage());
173	            }
174	        }
175	        logger.info("Finished refreshing schedules in {}ms", System.currentTimeMillis() - startTime);
176	    }
