178	    // A schedule-only Game carries null stats/leaders/scoringPlays collections;
179	    // merging one over an ingested game orphan-deletes those children. Only save
180	    // games that are new or still awaiting play (which have no details to lose) -
181	    // live games are owned by the 20s job and finished games don't change.
182	    private int saveScheduleGames(List<Game> games) {
183	        List<Long> ids = games.stream().map(game -> (long) game.getId()).toList();
184	        Map<Integer, String> existingStatuses = gameRepository.findAllById(ids).stream()
185	                .collect(Collectors.toMap(Game::getId,
186	                        game -> game.getGameStatus() == null ? "" : game.getGameStatus()));
187	
188	        List<Game> toSave = games.stream()
189	                .filter(game -> {
190	                    String status = existingStatuses.get(game.getId());
191	                    return status == null || status.isEmpty() || AWAITING_PLAY_STATUSES.contains(status);
192	                })
193	                .toList();
194	        gameRepository.saveAll(toSave);
195	        return toSave.size();
196	    }
197	
198	    // ESPN sometimes replaces a scheduled event with a new id (common with CFB
199	    // preseason placeholders), leaving the old id in our DB as a duplicate.
200	    // Delete scheduled games in the refreshed window that ESPN no longer lists.
201	    // An empty fetch skips pruning so a bad ESPN response can't wipe a schedule.
202	    private int pruneStaleScheduledGames(League league, List<Game> fetchedGames) {
203	        if (fetchedGames.isEmpty()) {
204	            return 0;
205	        }
206	        int year = Year.now().getValue();
207	        Instant windowStart = LocalDate.of(year, 1, 1).atStartOfDay(ZoneOffset.UTC).toInstant();
208	        Instant windowEnd = LocalDate.of(year + 1, 1, 1).atStartOfDay(ZoneOffset.UTC).toInstant();
209	        List<Integer> fetchedIds = fetchedGames.stream().map(Game::getId).toList();
210	        return gameRepository.deleteStaleScheduledGames(league, windowStart, windowEnd, fetchedIds);
211	    }
